var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"나는 줄곧 걷고 있었다.","JPN":"私はずっと歩いていた。","ENG":"I have been walking all this time...","TWN":"我一直走在，"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"차갑고 깊은 어둠에 잠긴 회랑의 경계선을.","JPN":"冷たくて深い闇に沈んだ回廊の境界線を。","ENG":"Along the edge of this cold, deep-dark corridor.","TWN":"淹沒在冰冷黑暗中的迴廊戒線上。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"subtitle","speaker":null,"text":{"KOREA":"오퍼레이션 <color=#ffd34c>클리포트 게임</color> ─ 개전\\n에크하르트 초월지식 학회 부학회장 레지나 맥크레디\\nCSE Lv. 5","JPN":"オペレーション<color=#ffd34c>クリフォトゲーム</color>─開戦\\nエクハルト超越知識学会の副学会長、レジーナ・マクレディー\\nCSE Lv. 5","ENG":"Operation <color=#ffd34c>Qliphoth Game</color> ─ Commence\\nRegina MacCready, Vice President of Eckhart's Society for Preternatural Research (ESPR)\\nCSE Lv. 5","TWN":"<color=#ffd34c>逆卡巴拉遊戲</color> - 開始\\n埃克哈特超越學會副學會長蕾佳娜·麥克蕾蒂\\nCSE Lv. 5"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>불완전한</color> 지식, <b>불완</b>전한 존<color=#ff3636>재들이 성</color>찬을 통해 완<b>전해</b>지리니......","JPN":"<color=#ff3636>不完全な</color>知識、<b>不完</b>全な存<color=#ff3636>在たちが聖</color>餐により完<b>全体と</b>なる……","ENG":"T<color=#ff3636>he feast</color> will <b>com</b>plete the imperfect <color=#ff3636>knowledge</color> and perfect the <b>imp</b>erfect beings.","TWN":"<color=#ff3636>不完整</color>的知識，<b>不完整</b>的存在將透過<color=#ff3636>盛宴</color>變得<b>完整</b>……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"여기는 이제 온통 당신의 잔해들뿐이군요.","JPN":"ここはもうあなたの残骸だらけですわね。","ENG":"All that is left here are your Remains.","TWN":"這裡如今都是你的殘骸。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"에델, 당신이 저들을 통해 지켜보고 있다는 건 알고 있습니다.","JPN":"エデル、あなたがあれらを通して私を監視しているということはわかっています。","ENG":"Edel, I know you have been using them to spy on me.","TWN":"艾瑟兒，我知道你正透過它們看著我。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"식사할 때 품위를 지키라고 그렇게 말했건만…….","JPN":"食事の際は品位を保つようにとあれほど言っておいたのに……","ENG":"Have I not told you before to have some class when you feast...?","TWN":"我一直叮囑讓你進餐的時候保持品味……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"적어도 다음에 올 사람을 위해 떠난 자리를 치워 두는 예절 정도는 지킬 수 없었나요?","JPN":"せめて次に座る人のために席の跡片付けをするくらいの礼儀は守れなかったんですの？","ENG":"Or could you at least clean up after yourself for the next person?","TWN":"就不能為了後來的人簡單收拾一下嗎？至少保持最基本的禮節吧？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"……정말이지 예나 지금이나 제멋대로군요.","JPN":"……まったく、昔も今も自分勝手なのは相変わらずですわね。","ENG":"...Then or now, you are always so selfish.","TWN":"……真是的，你還是一如既往的任性。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"좋습니다. 어차피 지금은 아무것도 귀에 들어오지 않겠죠.","JPN":"はあ、いいでしょう。どうせ今は何を言っても言葉が耳に入らないでしょうから。","ENG":"All right. I see you are not hearing anything I am saying right now.","TWN":"好吧。反正現在不管我說什麼，你都聽不進去。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"하지만 이것만은 명심하세요. 에델.","JPN":"ですが、これだけは覚えておいてください。エデル。","ENG":"But remember this, Edel.","TWN":"不過你要記住一件事，艾瑟兒。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"저는 당신을……","JPN":"私はあなたを……","ENG":"I am here...","TWN":"我是為了得到你……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"지식의 호수를 손에 넣기 위해 이 곳에 왔습니다.","JPN":"知識の湖を手に入れるためにここへやってきました。","ENG":"To make you mine, the Lake of Knowledge.","TWN":"得到知識湖水才來這裡的。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"이깟 얄팍한 저항으로 저를 막을 수 있다고 생각했다면, 지금이라도 재고해야 할 거예요.","JPN":"この程度の浅はかな抵抗で私を止められると思っているのなら、今からでも考え直すことをお勧めしますわ。","ENG":"You should reconsider if you think you can stop me with that feeble defiance.","TWN":"如果你以為用這種微不足道的抵抗就能阻止我，那你現在最好改變主意。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"아무한테도…… 당신을 넘겨 주진 않을 테니까.","JPN":"誰にも……あなたを渡すつもりなどありませんので。","ENG":"I am not going to... hand you over to anyone else.","TWN":"因為……我不會把你讓給任何人。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};